content.text:
I now have comprehensive knowledge of the codebase patterns. Here is the complete implementation plan.

---

# Stepper Compound Component - Implementation Plan

## Overview

This plan adds a fully-featured `Stepper` compound component to both the `base` and `radix` registries. The component is a pure custom compound component (no external primitive needed, following the Card model), with React context at two levels (root + per-item), controlled/uncontrolled support, horizontal and vertical orientations, and standard accessibility attributes.

---

## Step 1 - Create `apps/v4/registry/bases/base/ui/stepper.tsx`

This is the primary implementation file. The radix version is identical except for the `cn` import path.

```tsx
"use client"

import * as React from "react"

import { cn } from "@/registry/bases/base/lib/utils"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

type Orientation = "horizontal" | "vertical"

interface StepperContextValue {
  currentStep: number
  setStep: (step: number) => void
  orientation: Orientation
  totalSteps: number
}

interface StepperItemContextValue {
  step: number
  isActive: boolean
  isCompleted: boolean
}

// ---------------------------------------------------------------------------
// Contexts
// ---------------------------------------------------------------------------

const StepperContext = React.createContext<StepperContextValue>({
  currentStep: 0,
  setStep: () => {},
  orientation: "horizontal",
  totalSteps: 0,
})

const StepperItemContext = React.createContext<StepperItemContextValue>({
  step: 0,
  isActive: false,
  isCompleted: false,
})

// ---------------------------------------------------------------------------
// useStepper hook
// ---------------------------------------------------------------------------

function useStepper() {
  return React.useContext(StepperContext)
}

// ---------------------------------------------------------------------------
// Stepper (root)
// ---------------------------------------------------------------------------

interface StepperProps extends React.ComponentProps<"div"> {
  defaultStep?: number
  step?: number
  onStepChange?: (step: number) => void
  orientation?: Orientation
  totalSteps?: number
}

function Stepper({
  className,
  defaultStep = 0,
  step: controlledStep,
  onStepChange,
  orientation = "horizontal",
  totalSteps = 0,
  children,
  ...props
}: StepperProps) {
  const [uncontrolledStep, setUncontrolledStep] = React.useState(defaultStep)

  const isControlled = controlledStep !== undefined
  const currentStep = isControlled ? controlledStep : uncontrolledStep

  const setStep = React.useCallback(
    (next: number) => {
      if (!isControlled) {
        setUncontrolledStep(next)
      }
      onStepChange?.(next)
    },
    [isControlled, onStepChange]
  )

  return (
    <StepperContext.Provider
      value={{ currentStep, setStep, orientation, totalSteps }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "flex",
          orientation === "horizontal" ? "flex-col gap-4" : "flex-row gap-6",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

// ---------------------------------------------------------------------------
// StepperList
// ---------------------------------------------------------------------------

function StepperList({ className, ...props }: React.ComponentProps<"div">) {
  const { orientation } = React.useContext(StepperContext)

  return (
    <div
      data-slot="stepper-list"
      role="tablist"
      aria-orientation={orientation}
      className={cn(
        "flex",
        orientation === "horizontal"
          ? "flex-row items-start"
          : "flex-col",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperItem
// ---------------------------------------------------------------------------

interface StepperItemProps extends React.ComponentProps<"div"> {
  step: number
}

function StepperItem({
  className,
  step,
  children,
  ...props
}: StepperItemProps) {
  const { currentStep, orientation } = React.useContext(StepperContext)
  const isActive = currentStep === step
  const isCompleted = currentStep > step

  return (
    <StepperItemContext.Provider value={{ step, isActive, isCompleted }}>
      <div
        data-slot="stepper-item"
        data-active={isActive || undefined}
        data-completed={isCompleted || undefined}
        data-orientation={orientation}
        className={cn(
          "flex",
          orientation === "horizontal"
            ? "flex-1 flex-row items-center"
            : "flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

// ---------------------------------------------------------------------------
// StepperTrigger
// ---------------------------------------------------------------------------

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { setStep, orientation } = React.useContext(StepperContext)
  const { step, isActive, isCompleted } = React.useContext(StepperItemContext)

  return (
    <button
      data-slot="stepper-trigger"
      type="button"
      role="tab"
      aria-selected={isActive}
      aria-current={isActive ? "step" : undefined}
      data-active={isActive || undefined}
      data-completed={isCompleted || undefined}
      onClick={() => setStep(step)}
      className={cn(
        "flex shrink-0 cursor-pointer items-center gap-2 rounded-md text-left outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50",
        orientation === "vertical" && "flex-row",
        className
      )}
      {...props}
    >
      {/* Indicator circle */}
      <span
        className={cn(
          "flex size-8 shrink-0 items-center justify-center rounded-full text-sm font-medium transition-all",
          isActive &&
            "bg-primary text-primary-foreground ring-2 ring-primary ring-offset-2",
          isCompleted && "bg-primary text-primary-foreground",
          !isActive && !isCompleted && "bg-muted text-muted-foreground"
        )}
      >
        {isCompleted ? (
          <svg
            xmlns="http://www.w3.org/2000/svg"
            viewBox="0 0 24 24"
            fill="none"
            stroke="currentColor"
            strokeWidth="2.5"
            strokeLinecap="round"
            strokeLinejoin="round"
            className="size-4"
            aria-hidden="true"
          >
            <polyline points="20 6 9 17 4 12" />
          </svg>
        ) : (
          step + 1
        )}
      </span>
      {/* Title + description slot */}
      {children && (
        <span className="flex flex-col">{children}</span>
      )}
    </button>
  )
}

// ---------------------------------------------------------------------------
// StepperTitle
// ---------------------------------------------------------------------------

function StepperTitle({ className, ...props }: React.ComponentProps<"span">) {
  return (
    <span
      data-slot="stepper-title"
      className={cn("text-sm font-medium leading-none", className)}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperDescription
// ---------------------------------------------------------------------------

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"span">) {
  return (
    <span
      data-slot="stepper-description"
      className={cn("text-xs text-muted-foreground", className)}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperSeparator
// ---------------------------------------------------------------------------

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = React.useContext(StepperContext)
  const { isCompleted } = React.useContext(StepperItemContext)

  return (
    <div
      data-slot="stepper-separator"
      data-completed={isCompleted || undefined}
      aria-hidden="true"
      className={cn(
        "bg-border transition-colors data-[completed]:bg-primary",
        orientation === "horizontal"
          ? "mx-2 h-px flex-1"
          : "ml-4 mt-1 w-px self-stretch min-h-6",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperPanel
// ---------------------------------------------------------------------------

interface StepperPanelProps extends React.ComponentProps<"div"> {
  step: number
}

function StepperPanel({
  className,
  step,
  children,
  ...props
}: StepperPanelProps) {
  const { currentStep } = React.useContext(StepperContext)
  const isActive = currentStep === step

  if (!isActive) return null

  return (
    <div
      data-slot="stepper-panel"
      role="tabpanel"
      data-active={isActive || undefined}
      className={cn("flex-1 outline-none", className)}
      {...props}
    >
      {children}
    </div>
  )
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

export {
  Stepper,
  StepperList,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperPanel,
  useStepper,
}
```

### Key design notes for this file:

- The `"use client"` directive is required at line 1 because `useState`, `useCallback`, and `useContext` are all used.
- The checkmark SVG is inlined as a plain `<svg>` polyline (`points="20 6 9 17 4 12"`) rather than importing an icon library. This keeps the component self-contained with zero additional dependencies, matching the zero-dep Card pattern. Contrast this with components like combobox that use `IconPlaceholder` - those require the app's internal `@/app/(create)/components/icon-placeholder` import which is not appropriate for registry components meant to be installed by consumers.
- `StepperSeparator` reads both `orientation` from `StepperContext` and `isCompleted` from `StepperItemContext`. When `isCompleted` is true the separator turns `bg-primary` (fills the progress line behind completed steps).
- `StepperPanel` uses early `return null` when inactive - this is simpler and more correct than `hidden` CSS because it also unmounts panel content. Consumers who need to preserve panel state can wrap children in a `Suspense` boundary or implement keep-alive themselves.
- `totalSteps` is in context so consumers calling `useStepper()` can derive `isLast`, `isFirst`, etc. for navigation buttons in their own code. It does not affect internal component behavior.
- No `cn-stepper` semantic tokens are used anywhere because style CSS files cannot be modified.

