  const isLast = currentStep === totalSteps - 1

  return (
    <div className="flex gap-2">
      <Button
        variant="outline"
        size="sm"
        onClick={() => setStep(currentStep - 1)}
        disabled={isFirst}
      >
        Previous
      </Button>
      <Button
        size="sm"
        onClick={() => setStep(isLast ? 0 : currentStep + 1)}
      >
        {isLast ? "Start over" : "Next"}
      </Button>
    </div>
  )
}

// ---------------------------------------------------------------------------
// Horizontal stepper
// ---------------------------------------------------------------------------

function StepperHorizontal() {
  const [step, setStep] = React.useState(0)

  return (
    <Example title="Horizontal">
      <Stepper
        step={step}
        onStepChange={setStep}
        orientation="horizontal"
        totalSteps={STEPS.length}
        className="w-full"
      >
        <StepperList>
          {STEPS.map((s, index) => (
            <StepperItem key={s.title} step={index}>
              <StepperTrigger>
                <StepperTitle>{s.title}</StepperTitle>
                <StepperDescription>{s.description}</StepperDescription>
              </StepperTrigger>
              {index < STEPS.length - 1 && <StepperSeparator />}
            </StepperItem>
          ))}
        </StepperList>

        {STEPS.map((s, index) => (
          <StepperPanel key={s.title} step={index}>
            <div className="rounded-lg border bg-muted/40 p-4 text-sm text-muted-foreground">
              {s.content}
            </div>
          </StepperPanel>
        ))}

        <StepperNavigation />
      </Stepper>
    </Example>
  )
}

// ---------------------------------------------------------------------------
// Vertical stepper
// ---------------------------------------------------------------------------

function StepperVertical() {
  const [step, setStep] = React.useState(1)

  return (
    <Example title="Vertical">
      <Stepper
        step={step}
        onStepChange={setStep}
        orientation="vertical"
        totalSteps={STEPS.length}
        className="w-full"
      >
        <StepperList className="min-w-[180px]">
          {STEPS.map((s, index) => (
            <StepperItem key={s.title} step={index}>
              <StepperTrigger>
                <StepperTitle>{s.title}</StepperTitle>
                <StepperDescription>{s.description}</StepperDescription>
              </StepperTrigger>
              {index < STEPS.length - 1 && <StepperSeparator />}
            </StepperItem>
          ))}
        </StepperList>

        <div className="flex flex-1 flex-col gap-4">
          {STEPS.map((s, index) => (
            <StepperPanel key={s.title} step={index}>
              <div className="rounded-lg border bg-muted/40 p-4 text-sm text-muted-foreground">
                {s.content}
              </div>
            </StepperPanel>
          ))}
          <StepperNavigation />
        </div>
      </Stepper>
    </Example>
  )
}
```

### Key design notes for the example:

- The file carries its own `"use client"` directive because it uses `useState`.
- `StepperNavigation` is a standalone component that calls `useStepper()` to demonstrate the custom hook. This is an intentional design showcase for consumers.
- In the vertical layout, `StepperPanel` and `StepperNavigation` are placed inside a sibling `<div className="flex flex-1 flex-col gap-4">` alongside `StepperList`. This matches the layout model described in the requirements (panels in a separate column from the list).
- The `StepperSeparator` is rendered conditionally with `index < STEPS.length - 1` to suppress the trailing separator after the last step.
- `StepperVertical` starts at step 1 (`useState(1)`) so the demo immediately shows a completed first step and an active second step, making the visual states visible without interaction.

