# Stepper Compound Component — Implementation Plan

## Context

This plan adds a brand-new `Stepper` compound component to the shadcn/ui v4 library. No stepper component currently exists. The component will support multi-step wizards and onboarding flows with horizontal and vertical orientations, React context-based state sharing between sub-components, and both controlled and uncontrolled modes.

**Constraint**: Do NOT modify any existing component `.tsx` files. Only create new files and append registry entries to `_registry.ts` files.

---

## Architecture Overview

The component is a pure custom compound (no Radix/Base UI primitive needed — follows the `card.tsx` pattern). Two context levels share state:

1. **`StepperContext`** (root): `{ currentStep, setStep, orientation, totalSteps }`
2. **`StepperItemContext`** (per-item): `{ step, isActive, isCompleted }`

### Sub-components

| Component | Role |
|---|---|
| `Stepper` | Root container; provides `StepperContext`; controlled/uncontrolled |
| `StepperList` | Flex wrapper for all items (`flex-row` horizontal / `flex-col` vertical) |
| `StepperItem` | Single step; provides `StepperItemContext` |
| `StepperTrigger` | Clickable `<button>`; auto-renders indicator circle (number or ✓) |
| `StepperTitle` | Step title text (`<span>`) |
| `StepperDescription` | Step description text (`<span>`) |
| `StepperSeparator` | Connector line; fills with `bg-primary` when step is completed |
| `StepperPanel` | Content panel; renders only when its `step` matches `currentStep` |
| `useStepper` | Public hook exposing root context to consumers |

### Layout Model

**Horizontal** (`Stepper` is `flex flex-col`):
```
<Stepper>
  <StepperList>           ← flex flex-row items-start
    <StepperItem step={0}>  ← flex-1 flex-row items-center
      <StepperTrigger />    ← button: indicator + title + desc
      <StepperSeparator />  ← flex-1 h-px
    <StepperItem step={1}>  ...
  </StepperList>
  <StepperPanel step={0} /> ← shown when active, role="tabpanel"
  <StepperPanel step={1} />
</Stepper>
```

**Vertical** (`Stepper` is `flex flex-row gap-6`):
```
<Stepper>
  <StepperList>           ← flex flex-col
    <StepperItem step={0}>  ← flex-col
      <StepperTrigger />    ← flex-row items-center
      <StepperSeparator />  ← ml-4 w-px min-h-6 (centers under indicator)
  </StepperList>
  <div class="flex-1 flex-col gap-4">  ← user-provided wrapper
    <StepperPanel step={0} />
  </div>
</Stepper>
```

---

## Files to Create (4 new files)

### 1. `apps/v4/registry/bases/base/ui/stepper.tsx`

```tsx
"use client"

import * as React from "react"

import { cn } from "@/registry/bases/base/lib/utils"

// ── Types ─────────────────────────────────────────────────────────────────────

type Orientation = "horizontal" | "vertical"

interface StepperContextValue {
  currentStep: number
  setStep: (step: number) => void
  orientation: Orientation
  totalSteps: number
}

interface StepperItemContextValue {
  step: number
  isActive: boolean
  isCompleted: boolean
}

// ── Contexts ──────────────────────────────────────────────────────────────────

const StepperContext = React.createContext<StepperContextValue>({
  currentStep: 0,
  setStep: () => {},
  orientation: "horizontal",
  totalSteps: 0,
})

const StepperItemContext = React.createContext<StepperItemContextValue>({
  step: 0,
  isActive: false,
  isCompleted: false,
})

// ── Public hook ───────────────────────────────────────────────────────────────

function useStepper() {
  return React.useContext(StepperContext)
}

// ── Stepper (root) ────────────────────────────────────────────────────────────

interface StepperProps extends React.ComponentProps<"div"> {
  defaultStep?: number
  step?: number
  onStepChange?: (step: number) => void
  orientation?: Orientation
  totalSteps?: number
}

function Stepper({
  className,
  defaultStep = 0,
  step: controlledStep,
  onStepChange,
  orientation = "horizontal",
  totalSteps = 0,
  children,
  ...props
}: StepperProps) {
  const [uncontrolledStep, setUncontrolledStep] = React.useState(defaultStep)
  const isControlled = controlledStep !== undefined
  const currentStep = isControlled ? controlledStep : uncontrolledStep

  const setStep = React.useCallback(
    (next: number) => {
      if (!isControlled) setUncontrolledStep(next)
      onStepChange?.(next)
    },
    [isControlled, onStepChange]
  )

  return (
    <StepperContext.Provider value={{ currentStep, setStep, orientation, totalSteps }}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "flex",
          orientation === "horizontal" ? "flex-col gap-4" : "flex-row gap-6",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

// ── StepperList ───────────────────────────────────────────────────────────────

function StepperList({ className, ...props }: React.ComponentProps<"div">) {
  const { orientation } = React.useContext(StepperContext)
  return (
    <div
      data-slot="stepper-list"
      role="tablist"
      aria-orientation={orientation}
      className={cn(
        "flex",
        orientation === "horizontal" ? "flex-row items-start" : "flex-col",
        className
      )}
      {...props}
    />
  )
}

// ── StepperItem ───────────────────────────────────────────────────────────────

interface StepperItemProps extends React.ComponentProps<"div"> {
  step: number
}

function StepperItem({ className, step, children, ...props }: StepperItemProps) {
  const { currentStep, orientation } = React.useContext(StepperContext)
  const isActive = currentStep === step
  const isCompleted = currentStep > step

  return (
    <StepperItemContext.Provider value={{ step, isActive, isCompleted }}>
      <div
        data-slot="stepper-item"
        data-active={isActive || undefined}
        data-completed={isCompleted || undefined}
        className={cn(
          "flex",
          orientation === "horizontal" ? "flex-1 flex-row items-center" : "flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

// ── StepperTrigger ────────────────────────────────────────────────────────────

function StepperTrigger({ className, children, ...props }: React.ComponentProps<"button">) {
  const { setStep } = React.useContext(StepperContext)
  const { step, isActive, isCompleted } = React.useContext(StepperItemContext)

  return (
    <button
      data-slot="stepper-trigger"
      type="button"
      role="tab"
      aria-selected={isActive}
      aria-current={isActive ? "step" : undefined}
      data-active={isActive || undefined}
      data-completed={isCompleted || undefined}
      onClick={() => setStep(step)}
      className={cn(
        "flex shrink-0 cursor-pointer items-center gap-2 rounded-md text-left",
        "outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
        "disabled:pointer-events-none disabled:opacity-50",
        className
      )}
      {...props}
    >
      {/* Indicator circle (auto-rendered) */}
      <span
        data-slot="stepper-indicator"
        className={cn(
          "flex size-8 shrink-0 items-center justify-center rounded-full text-sm font-medium transition-all",
          isActive && "bg-primary text-primary-foreground ring-2 ring-primary ring-offset-2",
          isCompleted && "bg-primary text-primary-foreground",
          !isActive && !isCompleted && "bg-muted text-muted-foreground"
        )}
      >
        {isCompleted ? (
          <svg
            xmlns="http://www.w3.org/2000/svg"
            viewBox="0 0 24 24"
            fill="none"
            stroke="currentColor"
            strokeWidth="2.5"
            strokeLinecap="round"
            strokeLinejoin="round"
            className="size-4"
            aria-hidden="true"
          >
            <polyline points="20 6 9 17 4 12" />
          </svg>
        ) : (
          step + 1
        )}
      </span>
      {/* Title + Description slot */}
      {children && <span className="flex flex-col">{children}</span>}
    </button>
  )
}

// ── StepperTitle ──────────────────────────────────────────────────────────────

function StepperTitle({ className, ...props }: React.ComponentProps<"span">) {
  return (
    <span
      data-slot="stepper-title"
      className={cn("text-sm font-medium leading-none", className)}
      {...props}
    />
  )
}

// ── StepperDescription ────────────────────────────────────────────────────────

function StepperDescription({ className, ...props }: React.ComponentProps<"span">) {
  return (
    <span
      data-slot="stepper-description"
      className={cn("text-xs text-muted-foreground", className)}
      {...props}
    />
  )
}

// ── StepperSeparator ──────────────────────────────────────────────────────────

function StepperSeparator({ className, ...props }: React.ComponentProps<"div">) {
  const { orientation } = React.useContext(StepperContext)
  const { isCompleted } = React.useContext(StepperItemContext)

  return (
    <div
      data-slot="stepper-separator"
      data-completed={isCompleted || undefined}
      aria-hidden="true"
      className={cn(
        "bg-border transition-colors data-[completed]:bg-primary",
        orientation === "horizontal" ? "mx-2 h-px flex-1" : "ml-4 mt-1 w-px self-stretch min-h-6",
        className
      )}
      {...props}
    />
  )
}

// ── StepperPanel ──────────────────────────────────────────────────────────────

interface StepperPanelProps extends React.ComponentProps<"div"> {
  step: number
}

function StepperPanel({ className, step, children, ...props }: StepperPanelProps) {
  const { currentStep } = React.useContext(StepperContext)
  if (currentStep !== step) return null

  return (
    <div
      data-slot="stepper-panel"
      role="tabpanel"
      data-active
      className={cn("flex-1 outline-none", className)}
      {...props}
    >
      {children}
    </div>
  )
}

// ── Exports ───────────────────────────────────────────────────────────────────

export {
  Stepper,
  StepperList,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperPanel,
  useStepper,
}
```

**Design notes:**
- `"use client"` required because of `useState`/`useCallback`/`useContext`
- Checkmark is an inline SVG polyline — no lucide import needed, zero extra dependencies
- `StepperSeparator` uses `data-[completed]:bg-primary` Tailwind data-attribute selector to fill the progress line
- `StepperPanel` uses early `return null` (not hidden CSS) to unmount inactive panels
- No `cn-stepper*` semantic tokens — only direct Tailwind utilities (cannot modify style CSS files)
- `totalSteps` in context allows the `useStepper()` hook to power navigation buttons externally

---

### 2. `apps/v4/registry/bases/radix/ui/stepper.tsx`

Identical to the base version with **one line changed**:
```diff
- import { cn } from "@/registry/bases/base/lib/utils"
+ import { cn } from "@/registry/bases/radix/lib/utils"
```

---

### 3. `apps/v4/registry/bases/base/examples/stepper-example.tsx`

```tsx
"use client"

