}

// ── StepperDescription ────────────────────────────────────────────────────────

function StepperDescription({ className, ...props }: React.ComponentProps<"span">) {
  return (
    <span
      data-slot="stepper-description"
      className={cn("text-xs text-muted-foreground", className)}
      {...props}
    />
  )
}

// ── StepperSeparator ──────────────────────────────────────────────────────────

function StepperSeparator({ className, ...props }: React.ComponentProps<"div">) {
  const { orientation } = React.useContext(StepperContext)
  const { isCompleted } = React.useContext(StepperItemContext)

  return (
    <div
      data-slot="stepper-separator"
      data-completed={isCompleted || undefined}
      aria-hidden="true"
      className={cn(
        "bg-border transition-colors data-[completed]:bg-primary",
        orientation === "horizontal" ? "mx-2 h-px flex-1" : "ml-4 mt-1 w-px self-stretch min-h-6",
        className
      )}
      {...props}
    />
  )
}

// ── StepperPanel ──────────────────────────────────────────────────────────────

interface StepperPanelProps extends React.ComponentProps<"div"> {
  step: number
}

function StepperPanel({ className, step, children, ...props }: StepperPanelProps) {
  const { currentStep } = React.useContext(StepperContext)
  if (currentStep !== step) return null

  return (
    <div
      data-slot="stepper-panel"
      role="tabpanel"
      data-active
      className={cn("flex-1 outline-none", className)}
      {...props}
    >
      {children}
    </div>
  )
}

// ── Exports ───────────────────────────────────────────────────────────────────

export {
  Stepper,
  StepperList,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperPanel,
  useStepper,
}
```

**Design notes:**
- `"use client"` required because of `useState`/`useCallback`/`useContext`
- Checkmark is an inline SVG polyline — no lucide import needed, zero extra dependencies
- `StepperSeparator` uses `data-[completed]:bg-primary` Tailwind data-attribute selector to fill the progress line
- `StepperPanel` uses early `return null` (not hidden CSS) to unmount inactive panels
- No `cn-stepper*` semantic tokens — only direct Tailwind utilities (cannot modify style CSS files)
- `totalSteps` in context allows the `useStepper()` hook to power navigation buttons externally

---

### 2. `apps/v4/registry/bases/radix/ui/stepper.tsx`

Identical to the base version with **one line changed**:
```diff
- import { cn } from "@/registry/bases/base/lib/utils"
+ import { cn } from "@/registry/bases/radix/lib/utils"
```

---

### 3. `apps/v4/registry/bases/base/examples/stepper-example.tsx`

```tsx
"use client"

import * as React from "react"

import {
  Example,
  ExampleWrapper,
} from "@/registry/bases/base/components/example"
import { Button } from "@/registry/bases/base/ui/button"
import {
  Stepper,
  StepperDescription,
  StepperItem,
  StepperList,
  StepperPanel,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
  useStepper,
} from "@/registry/bases/base/ui/stepper"

export default function StepperExample() {
  return (
    <ExampleWrapper className="w-full max-w-4xl lg:grid-cols-1 2xl:max-w-4xl 2xl:grid-cols-1">
      <StepperHorizontal />
      <StepperVertical />
    </ExampleWrapper>
  )
}

const STEPS = [
  { title: "Account",     description: "Create your account",      content: "Fill in your email address and create a password to get started. We will send a confirmation link to verify your email." },
  { title: "Profile",     description: "Set up your profile",       content: "Tell us a bit about yourself. Add a display name and optionally a profile picture that other members will see." },
  { title: "Preferences", description: "Customize your experience", content: "Choose your notification preferences, timezone, and language settings. You can change these later in your account settings." },
  { title: "Finish",      description: "Review and confirm",        content: "Everything looks good! Review your information and click Finish to complete your setup." },
]

// Demonstrates useStepper() hook — reads context from parent Stepper
function StepperNavigation() {
  const { currentStep, setStep, totalSteps } = useStepper()
  return (
    <div className="flex gap-2">
      <Button variant="outline" size="sm" onClick={() => setStep(currentStep - 1)} disabled={currentStep === 0}>
        Previous
      </Button>
      <Button size="sm" onClick={() => setStep(currentStep === totalSteps - 1 ? 0 : currentStep + 1)}>
        {currentStep === totalSteps - 1 ? "Start over" : "Next"}
      </Button>
    </div>
  )
}

function StepperHorizontal() {
  const [step, setStep] = React.useState(0)
  return (
    <Example title="Horizontal">
      <Stepper step={step} onStepChange={setStep} orientation="horizontal" totalSteps={STEPS.length} className="w-full">
        <StepperList>
          {STEPS.map((s, i) => (
            <StepperItem key={s.title} step={i}>
              <StepperTrigger>
                <StepperTitle>{s.title}</StepperTitle>
                <StepperDescription>{s.description}</StepperDescription>
              </StepperTrigger>
              {i < STEPS.length - 1 && <StepperSeparator />}
            </StepperItem>
          ))}
        </StepperList>
        {STEPS.map((s, i) => (
          <StepperPanel key={s.title} step={i}>
            <div className="rounded-lg border bg-muted/40 p-4 text-sm text-muted-foreground">
              {s.content}
            </div>
          </StepperPanel>
        ))}
        <StepperNavigation />
      </Stepper>
    </Example>
  )
}

function StepperVertical() {
  const [step, setStep] = React.useState(1)   // start at step 1 to show completed state
  return (
    <Example title="Vertical">
      <Stepper step={step} onStepChange={setStep} orientation="vertical" totalSteps={STEPS.length} className="w-full">
        <StepperList className="min-w-[180px]">
          {STEPS.map((s, i) => (
            <StepperItem key={s.title} step={i}>
              <StepperTrigger>
                <StepperTitle>{s.title}</StepperTitle>
                <StepperDescription>{s.description}</StepperDescription>
              </StepperTrigger>
              {i < STEPS.length - 1 && <StepperSeparator />}
            </StepperItem>
          ))}
        </StepperList>
        <div className="flex flex-1 flex-col gap-4">
          {STEPS.map((s, i) => (
            <StepperPanel key={s.title} step={i}>
              <div className="rounded-lg border bg-muted/40 p-4 text-sm text-muted-foreground">
                {s.content}
              </div>
            </StepperPanel>
          ))}
          <StepperNavigation />
        </div>
      </Stepper>
    </Example>
  )
}
```

