"use client"

import * as React from "react"

import { cn } from "@/registry/bases/radix/lib/utils"

// ─── Stepper Root Context ─────────────────────────────────────────────────────

interface StepperContextValue {
  value: number
  onValueChange: (value: number) => void
  orientation: "horizontal" | "vertical"
}

const StepperContext = React.createContext<StepperContextValue | null>(null)

function useStepper(): StepperContextValue {
  const ctx = React.useContext(StepperContext)
  if (!ctx) {
    throw new Error("`useStepper` must be used within a `<Stepper>`")
  }
  return ctx
}

// ─── StepperItem Context ──────────────────────────────────────────────────────

interface StepperItemContextValue {
  step: number
  isActive: boolean
  isCompleted: boolean
}

const StepperItemContext =
  React.createContext<StepperItemContextValue | null>(null)

function useStepperItem(): StepperItemContextValue {
  const ctx = React.useContext(StepperItemContext)
  if (!ctx) {
    throw new Error("`useStepperItem` must be used within a `<StepperItem>`")
  }
  return ctx
}

// ─── Stepper ──────────────────────────────────────────────────────────────────

interface StepperProps extends Omit<React.ComponentProps<"div">, "defaultValue"> {
  value?: number
  defaultValue?: number
  onValueChange?: (value: number) => void
  orientation?: "horizontal" | "vertical"
}

function Stepper({
  value: valueProp,
  defaultValue = 0,
  onValueChange,
  orientation = "horizontal",
  className,
  ...props
}: StepperProps) {
  const [internalValue, setInternalValue] = React.useState(defaultValue)
  const isControlled = valueProp !== undefined
  const value = isControlled ? valueProp : internalValue

  const handleValueChange = React.useCallback(
    (newValue: number) => {
      if (!isControlled) setInternalValue(newValue)
      onValueChange?.(newValue)
    },
    [isControlled, onValueChange]
  )

  return (
    <StepperContext.Provider
      value={{ value, onValueChange: handleValueChange, orientation }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "flex",
          orientation === "horizontal" ? "flex-col gap-4" : "flex-row gap-6",
          className
        )}
        {...props}
      />
    </StepperContext.Provider>
  )
}

// ─── StepperList ──────────────────────────────────────────────────────────────

function StepperList({ className, ...props }: React.ComponentProps<"div">) {
  const { orientation } = useStepper()

  return (
    <div
      data-slot="stepper-list"
      data-orientation={orientation}
      className={cn(
        "flex",
        orientation === "horizontal" ? "flex-row items-center" : "flex-col",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperItem ─────────────────────────────────────────────────────────────

interface StepperItemProps extends React.ComponentProps<"div"> {
  step: number
}

function StepperItem({ step, className, ...props }: StepperItemProps) {
  const { value, orientation } = useStepper()
  const isActive = value === step
  const isCompleted = value > step

  return (
    <StepperItemContext.Provider value={{ step, isActive, isCompleted }}>
      <div
        data-slot="stepper-item"
        data-active={isActive ? "" : undefined}
        data-completed={isCompleted ? "" : undefined}
        className={cn(
          "group/stepper-item flex",
          orientation === "horizontal"
            ? "flex-1 flex-row items-center"
            : "flex-col",
          className
        )}
        {...props}
      />
    </StepperItemContext.Provider>
  )
}

// ─── StepperTrigger ───────────────────────────────────────────────────────────

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { onValueChange } = useStepper()
  const { step, isActive, isCompleted } = useStepperItem()

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      data-active={isActive ? "" : undefined}
      data-completed={isCompleted ? "" : undefined}
      aria-current={isActive ? "step" : undefined}
      onClick={() => onValueChange(step)}
      className={cn(
        "inline-flex cursor-pointer items-center gap-3 rounded-md outline-none transition-colors",
        "focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
        "disabled:pointer-events-none disabled:opacity-50",
        className
      )}
      {...props}
    >
      <span
        data-slot="stepper-indicator"
        aria-hidden="true"
        className={cn(
          "flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-sm font-semibold transition-colors",
          isCompleted || isActive
            ? "border-primary bg-primary text-primary-foreground"
            : "border-muted-foreground/40 bg-background text-muted-foreground"
        )}
      >
        {isCompleted ? (
          <svg
            xmlns="http://www.w3.org/2000/svg"
            viewBox="0 0 24 24"
            fill="none"
            stroke="currentColor"
            strokeWidth={2.5}
            strokeLinecap="round"
            strokeLinejoin="round"
            className="size-4"
            aria-hidden="true"
          >
            <polyline points="20 6 9 17 4 12" />
          </svg>
        ) : (
          step + 1
        )}
      </span>
      {children && (
        <span className="flex flex-col gap-0.5 text-left">{children}</span>
      )}
    </button>
  )
}

// ─── StepperTitle ─────────────────────────────────────────────────────────────

function StepperTitle({ className, ...props }: React.ComponentProps<"span">) {
  const { isActive } = useStepperItem()

  return (
    <span
      data-slot="stepper-title"
      data-active={isActive ? "" : undefined}
      className={cn(
        "text-sm font-medium leading-none transition-colors",
        isActive ? "text-foreground" : "text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperDescription ───────────────────────────────────────────────────────

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-xs text-muted-foreground", className)}
      {...props}
    />
  )
}

// ─── StepperSeparator ─────────────────────────────────────────────────────────

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()
  const { isCompleted } = useStepperItem()

  return (
    <div
      data-slot="stepper-separator"
      data-completed={isCompleted ? "" : undefined}
      aria-hidden="true"
      className={cn(
        "shrink-0 rounded-full bg-muted-foreground/30 transition-colors data-[completed]:bg-primary",
        orientation === "horizontal"
          ? "mx-2 h-0.5 flex-1"
          : "ml-[15px] my-1 h-8 w-0.5",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperPanel ─────────────────────────────────────────────────────────────

interface StepperPanelProps extends React.ComponentProps<"div"> {
  step: number
}

function StepperPanel({ step, className, ...props }: StepperPanelProps) {
  const { value } = useStepper()

  if (value !== step) return null

  return (
    <div
      data-slot="stepper-panel"
      className={cn("flex-1", className)}
      {...props}
    />
  )
}

// ─── Exports ──────────────────────────────────────────────────────────────────

export {
  Stepper,
  StepperList,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperPanel,
  useStepper,
}

