        <StepperList>
          {STEPS.map((s, i) => (
            <StepperItem key={i} step={i}>
              <StepperTrigger>
                <StepperTitle>{s.title}</StepperTitle>
              </StepperTrigger>
              {i < STEPS.length - 1 && <StepperSeparator />}
            </StepperItem>
          ))}
        </StepperList>

        {panelContent.map((content, i) => (
          <StepperPanel
            key={i}
            step={i}
            className="rounded-lg border bg-muted/40 p-6"
          >
            <p className="text-sm text-muted-foreground">{content}</p>
          </StepperPanel>
        ))}

        <StepperNavigation totalSteps={STEPS.length} />
      </Stepper>
    </Example>
  )
}

