    "Enter your email and choose a secure password to get started.",
    "Tell us a bit about yourself so we can personalize your experience.",
    "Everything looks great! Click Finish to complete your onboarding.",
  ]

  return (
    <Example title="Vertical">
      <Stepper orientation="vertical" defaultValue={1} className="w-full">
        <StepperList className="min-w-[160px]">
          {STEPS.map((s, i) => (
            <StepperItem key={i} step={i}>
              <StepperTrigger>
                <StepperTitle>{s.title}</StepperTitle>
                <StepperDescription>{s.description}</StepperDescription>
              </StepperTrigger>
              {i < STEPS.length - 1 && <StepperSeparator />}
            </StepperItem>
          ))}
        </StepperList>

        <div className="flex-1">
          {panelContent.map((content, i) => (
            <StepperPanel
              key={i}
              step={i}
              className="rounded-lg border bg-muted/40 p-6"
            >
              <p className="text-sm font-medium">{STEPS[i].title}</p>
              <p className="mt-1 text-sm text-muted-foreground">{content}</p>
            </StepperPanel>
          ))}
        </div>
      </Stepper>
    </Example>
  )
}

